import { Type } from './Type.js';
/** Maps a database TINYINT column to a JS `number`. */
export class TinyIntType extends Type {
    getColumnType(prop, platform) {
        return platform.getTinyIntTypeDeclarationSQL(prop);
    }
    compareAsType() {
        return 'number';
    }
    /* v8 ignore next */
    ensureComparable() {
        return false;
    }
}
